<?php
namespace App\Http\Controllers\Inventory; use App\Http\Controllers\Controller; use App\Models\Inventory\{InventoryCondition,InventoryItem,InventoryLocation,InventoryStockOpname,InventoryTransaction}; use App\Services\Inventory\InventoryLedgerService; use Illuminate\Http\Request;
class InventoryTransactionController extends Controller{public function index(){return view('inventory.transactions.index',['transactions'=>InventoryTransaction::with('item','fromLocation','toLocation','fromCondition','toCondition')->latest()->paginate(20)]);} public function create(){return view('inventory.transactions.form',$this->refs());} public function store(Request $r, InventoryLedgerService $svc){$d=$r->validate(['type'=>'required|in:opening,addition,reduction,transfer,condition_change,correction','transaction_date'=>'required|date','inventory_item_id'=>'required|exists:inventory_items,id','from_location_id'=>'nullable|exists:inventory_locations,id','to_location_id'=>'nullable|exists:inventory_locations,id','from_condition_id'=>'nullable|exists:inventory_conditions,id','to_condition_id'=>'nullable|exists:inventory_conditions,id','quantity'=>'required|integer|min:1','reference_number'=>'nullable|max:120','reason'=>'required|min:5|max:255','notes'=>'nullable']);$svc->post($d,$r->user()->id);return redirect()->route('inventory.transactions.index')->with('status','Transaksi inventaris diposting.');} public function reverse(Request $r,InventoryTransaction $transaction,InventoryLedgerService $svc){$r->validate(['reason'=>'required|min:5']);$svc->reverse($transaction,$r->reason,$r->user()->id);return back()->with('status','Transaksi dibatalkan melalui reversal.');} private function refs():array{return ['items'=>InventoryItem::where('is_active',1)->get(),'locations'=>InventoryLocation::where('is_active',1)->get(),'conditions'=>InventoryCondition::where('is_active',1)->get()];}}
